def solve(grid):
    import numpy as np
    from collections import defaultdict, deque

    grid = [list(row) for row in grid]
    H, W = len(grid), len(grid[0])

    # Step 1: Find all 1 and 2 colored cells
    ones = [(r, c) for r in range(H) for c in range(W) if grid[r][c] == 1]
    twos = [(r, c) for r in range(H) for c in range(W) if grid[r][c] == 2]

    # Step 2: Group by enclosing border color to find templates
    def get_border_for_pattern(r, c):
        for dist in range(1, 5):
            for dr in range(-dist, dist+1):
                for dc in range(-dist, dist+1):
                    if abs(dr) == dist or abs(dc) == dist:
                        nr, nc = r+dr, c+dc
                        if 0 <= nr < H and 0 <= nc < W:
                            v = grid[nr][nc]
                            if v not in (0, 1, 2, 4):
                                return v
        return None

    templates = defaultdict(lambda: {'ones': [], 'twos': []})
    for r, c in ones:
        bc = get_border_for_pattern(r, c)
        if bc is not None:
            templates[bc]['ones'].append((r, c))
    for r, c in twos:
        bc = get_border_for_pattern(r, c)
        if bc is not None:
            templates[bc]['twos'].append((r, c))

