    for bc, data in templates.items():
        o1, o2 = data['ones'], data['twos']
        if not o1 or not o2:
            continue
        c1r = sum(r for r,c in o1) / len(o1)
        c1c = sum(c for r,c in o1) / len(o1)
        c2r = sum(r for r,c in o2) / len(o2)
        c2c = sum(c for r,c in o2) / len(o2)

