        dc = c2c - c1c
        dr_sign = (1 if dr > 0.01 else (-1 if dr < -0.01 else 0))
        dc_sign = (1 if dc > 0.01 else (-1 if dc < -0.01 else 0))
        directions[bc] = (dr_sign, dc_sign)

    # Step 4: Find all 4s and determine their enclosing shape
    def get_enclosing_color(r, c):
        visited = set()
        queue = deque([(r, c)])
        visited.add((r, c))
        border_colors = {}

